import React, { useState } from 'react';
import { 
  LayoutDashboard, FileSpreadsheet, Bot, Settings, Play, Download, 
  AlertCircle, CheckCircle2, CalendarDays, ClipboardPaste, Loader2,
  Database, Building2, Cpu, CalendarClock, Plus, Trash2, Save
} from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [fcstInput, setFcstInput] = useState('');
  const [sompInput, setSompInput] = useState('');
  const [results, setResults] = useState([]);
  const [status, setStatus] = useState({ type: 'idle', message: '' });

  const [mappingRules, setMappingRules] = useState(() => {
    const saved = localStorage.getItem('pskMasterData');
    return saved ? JSON.parse(saved) : {
      lineMap: { 'T1': 'SEC-T1(USA)', 'P1F': 'SEC-P1(F)(KR)' },
      fabClientMap: { 'SEC-T1(USA)': 'Samsung Electronics' },
      modelMap: { 'SUPRA-N': { model: 'SUPRA N', pm: 0 } },
      atmMaster: [{ id: 'ATM-102', start: '2026-01-13', end: '2026-01-29', maxCapa: 6 }]
    };
  });

  const saveRules = (newRules) => {
    setMappingRules(newRules);
    localStorage.setItem('pskMasterData', JSON.stringify(newRules));
  };

  const [newLine, setNewLine] = useState({ client: '', line: '', fab: '' });
  const [newModel, setNewModel] = useState({ raw: '', somp: '', pm: 0 });
  const [newAtm, setNewAtm] = useState({ id: '', start: '', end: '', capa: 6 });

  const addLineRule = () => {
    const updated = { ...mappingRules };
    updated.lineMap[newLine.line] = newLine.fab;
    updated.fabClientMap[newLine.fab] = newLine.client;
    saveRules(updated);
  };

  const addModelRule = () => {
    const updated = { ...mappingRules };
    updated.modelMap[newModel.raw] = { model: newModel.somp, pm: parseInt(newModel.pm) || 0 };
    saveRules(updated);
  };

  const addAtmRule = () => {
    const updated = { ...mappingRules };
    updated.atmMaster = [...updated.atmMaster, { ...newAtm, maxCapa: parseInt(newAtm.capa) || 6 }];
    saveRules(updated);
  };

  const removeLineRule = (line) => { const updated = { ...mappingRules }; delete updated.lineMap[line]; saveRules(updated); };
  const removeModelRule = (raw) => { const updated = { ...mappingRules }; delete updated.modelMap[raw]; saveRules(updated); };
  const removeAtmRule = (id) => { const updated = { ...mappingRules }; updated.atmMaster = updated.atmMaster.filter(atm => atm.id !== id); saveRules(updated); };

  return (
    <div className="flex h-screen bg-gray-50 font-sans">
      <aside className="w-64 bg-[#1a233a] text-white flex flex-col shadow-xl">
        <div className="h-16 flex items-center px-6 bg-[#111827] font-bold text-lg"><Bot className="mr-2 text-blue-400" /> Team AI Portal</div>
        <nav className="p-4 space-y-2">
          <button onClick={() => setActiveTab('fcst')} className={`w-full p-3 rounded flex items-center ${activeTab === 'fcst' ? 'bg-blue-600' : 'hover:bg-gray-800'}`}><CalendarDays className="mr-2" size={18}/> FCST 스케줄러</button>
          <button onClick={() => setActiveTab('master')} className={`w-full p-3 rounded flex items-center ${activeTab === 'master' ? 'bg-blue-600' : 'hover:bg-gray-800'}`}><Database className="mr-2" size={18}/> 데이터 관리</button>
        </nav>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        {activeTab === 'fcst' ? (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">FCST 자동 스케줄링</h2>
            <div className="grid grid-cols-2 gap-4">
              <textarea className="w-full h-48 p-4 border rounded" placeholder="FCST 데이터..." onChange={e => setFcstInput(e.target.value)} value={fcstInput}/>
              <textarea className="w-full h-48 p-4 border rounded" placeholder="SOMP 데이터..." onChange={e => setSompInput(e.target.value)} value={sompInput}/>
            </div>
            <button onClick={() => setStatus({type: 'success', message: '배정 완료'})} className="bg-blue-600 text-white px-8 py-3 rounded-lg font-bold">배정 시작</button>
          </div>
        ) : (
          <div className="space-y-8">
            <h2 className="text-2xl font-bold">마스터 데이터 관리</h2>
            <div className="bg-white p-6 rounded shadow border">
              <h3 className="font-bold mb-4 flex items-center"><CalendarClock className="mr-2"/> ATM 스케줄 에디터</h3>
              <table className="w-full border-collapse border">
                <thead><tr className="bg-gray-50"><th className="border p-2">ID</th><th className="border p-2">기간</th><th className="border p-2">삭제</th></tr></thead>
                <tbody>{mappingRules.atmMaster.map(a => <tr key={a.id}><td className="border p-2">{a.id}</td><td className="border p-2">{a.start} ~ {a.end}</td><td className="border p-2"><button onClick={() => removeAtmRule(a.id)} className="text-red-500"><Trash2 size={18}/></button></td></tr>)}</tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}
